    except SyntaxError as e:
        raise ValueError(*e.args)
    for child in root:
        raw[child.tag] = child.text
    formatted = self.format(raw)
    msg_type = formatted['type']
    msg_parser = getattr(self, 'parse_%s' % msg_type, None)
