def extract_ngram_filter(pos_seq, regex=SimpleNP, minlen=1, maxlen=8):
    ss = coarse_tag_str(pos_seq)

    def gen():
        for s in xrange(len(ss)):
            for n in xrange(minlen, 1 + min(maxlen, len(ss) - s)):
                e = s + n
                substr = ss[s:e]
                if re.match(regex + '$', substr):
                    yield (s, e)
    return list(gen())

def default(self, obj):
    if isinstance(obj, np.ndarray):
        if obj.flags['C_CONTIGUOUS']:
            obj_data = obj.data
        else:
            cont_obj = np.ascontiguousarray(obj)
            assert cont_obj.flags['C_CONTIGUOUS']
            obj_data = cont_obj.data
        if has_blosc:
            obj_data = blosc.compress(obj_data, typesize=8)
        data_b64 = base64.b64encode(obj_data)
        if sys.version_info >= (3, 0):
            data_b64 = data_b64.decode('utf-8')
        return dict(__ndarray__=data_b64, dtype=str(obj.dtype), shape=obj.shape)
    return json.JSONEncoder.default(self, obj)

def housecode_to_index(housecode):
    match = re.search('^([A-P])(\\d{1,2})$', housecode.upper())
    if match:
        house_index = int(match.group(2))
        if 1 <= house_index <= 16:
            return (ord(match.group(1)) - ord('A')) * 16 + house_index - 1
    raise ValueError('Invalid X10 housecode: %s' % housecode)

