            stream.data_available.clear()
            stream.data_unoccupied.set()
            if time.time() - start_time > seconds:
                break
    return found

def bend(mapping, source, context=None):
    context = {} if context is None else context
    transport = Transport(source, context)
    return _bend(mapping, transport)

def before(f, chain=False):

    def decorator(g):

        @wraps(g)
        def h(*args, **kargs):
            if chain:
                return g(f(*args, **kargs))
            else:
                f(*args, **kargs)
                return g(*args, **kargs)
        return h
    return decorator

def get_parser(self, **kwargs):
    self.parser = argparse.ArgumentParser(prog=self.prog_name, description=self._desc, add_help=False, **kwargs)
    if self.use_config_file:
        self.parser.add_argument('--config-file', action='store', help='Other configuration file.')
